  Map<String, dynamic> _sanitizeMap(Map<String, dynamic>? data) {
    if (data == null) return {};
    
    return data.map((key, value) {
      if (_isSensitiveField(key)) {
        return MapEntry(key, _maskValue(value));
      }
      if (value is Map<String, dynamic>) {
        return MapEntry(key, _sanitizeMap(value));
      }
      if (value is List) {
        return MapEntry(key, _sanitizeList(value));
      }
      return MapEntry(key, value);
    });
  }

  List<dynamic> _sanitizeList(List<dynamic> list) {
    return list.map((item) {
      if (item is Map<String, dynamic>) {
        return _sanitizeMap(item);
      }
      return item;
    }).toList();
  }

  dynamic _sanitizeData(dynamic data) {
    if (data == null) return null;
    
    if (data is Map<String, dynamic>) {
      return _sanitizeMap(data);
    }
    
    if (data is String) {
      try {
        final decoded = jsonDecode(data);
        if (decoded is Map<String, dynamic>) {
          return jsonEncode(_sanitizeMap(decoded));
        }
      } catch (_) {}
    }
    
    return data;
  }

  bool _isSensitiveField(String key) {
    final lowerKey = key.toLowerCase();
    return _sensitiveFields.any((field) => lowerKey.contains(field.toLowerCase()));
  }

  String _maskValue(dynamic value) {
    if (value == null) return '***';
    final str = value.toString();
    if (str.length <= 4) return '***';
    return '${str.substring(0, 2)}***${str.substring(str.length - 2)}';
  }

  String _maskEmail(String email) {
    final parts = email.split('@');
    if (parts.length != 2) return '***@***.***';
    final username = parts[0];
    final domain = parts[1];
    final maskedUsername = username.length > 2 
        ? '${username.substring(0, 2)}***' 
        : '***';
    return '$maskedUsername@$domain';
  }

  String _maskId(String id) {
